script:
schedules = frappe.get_all(
    "Billing Schedule",
    filters={
        "status": "Pending",
        "billing_date": ["<=", frappe.utils.today()]
    },
    fields=[
        "name", "customer", "contract",
        "amount", "billing_date"
    ]
)

for schedule in schedules:
    try:
        invoice = frappe.new_doc("Sales Invoice")
        invoice.customer = schedule.customer
        invoice.posting_date = schedule.billing_date
        invoice.due_date = frappe.utils.add_days(schedule.billing_date, 30)

        invoice.append("items", {
            "item_code": "Rental Charge",
            "item_name": f"Rental - {schedule.contract}",
            "description": f"Rental billing for contract {schedule.contract}",
            "qty": 1,
            "rate": schedule.amount,
            "amount": schedule.amount
        })

        invoice.insert(ignore_permissions=True)

        frappe.db.set_value("Billing Schedule", schedule.name, {
            "status": "Invoiced",
            "sales_invoice": invoice.name
        })

        frappe.db.commit()

    except Exception as e:
        frappe.log_error(
            message=str(e),
            title=f"Invoice creation failed for schedule {schedule.name}"
        )
